        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new OptionSnapshotsResponse();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[OptionSnapshotsResponse](sbeTemplateId=");
            builder.Append(OptionSnapshotsResponse.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(OptionSnapshotsResponse.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != OptionSnapshotsResponse.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(OptionSnapshotsResponse.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != OptionSnapshotsResponse.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(OptionSnapshotsResponse.BlockLength);
            builder.Append("):");

            builder.Append("RequestId=");
            builder.Append(this.RequestId);
            builder.Append('|');
            builder.Append("UpdateFound=");
            builder.Append(this.UpdateFound);
            builder.Append('|');
            builder.Append("Snapshots=[");
            var snapshots = this.Snapshots;
            if (snapshots.Count > 0)
            {
                var first = true;
                while (snapshots.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    snapshots.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
